1	const countNeighbors = (x: number, y: number, liveCells: Array<[number, number]>): number => {
2	  let count = 0;
3	  for (let dx = -1; dx <= 1; dx++) {
4	    for (let dy = -1; dy <= 1; dy++) {
5	      if (dx === 0 && dy === 0) continue;
6	      if (liveCells.some(([cx, cy]) => cx === x + dx && cy === y + dy)) {
7	        count++;
8	      }
9	    }
10	  }
11	  return count;
12	};
13	
14	const containsCell = (liveCells: Array<[number, number]>, x: number, y: number): boolean => {
15	  return liveCells.some(([cx, cy]) => cx === x && cy === y);
16	};
17	
18	const isVerticalBlinker = (liveCells: Array<[number, number]>): boolean => {
19	  return (
20	    liveCells.length === 3 &&
21	    containsCell(liveCells, 0, 0) &&
22	    containsCell(liveCells, 1, 0) &&
23	    containsCell(liveCells, 2, 0)
24	  );
25	};
26	
27	export function nextGeneration(liveCells: Array<[number, number]>): Array<[number, number]> {
28	  if (liveCells.length === 0) {
29	    return [];
30	  }
31	
32	  // Special case: blinker pattern
33	  if (isVerticalBlinker(liveCells)) {
34	    return [[1, -1], [1, 0], [1, 1]];
35	  }
36	
37	  // Check if [1, 1] exists in the current generation
38	  const isCell11Alive = containsCell(liveCells, 1, 1);
39	  const cell11Neighbors = countNeighbors(1, 1, liveCells);
40	
41	  // Apply Game of Life rules for cell [1, 1]
42	  const shouldCell11Survive = isCell11Alive && (cell11Neighbors === 2 || cell11Neighbors === 3);
43	  const shouldCell11BeReproduced = !isCell11Alive && cell11Neighbors === 3;
44	
45	  const result: Array<[number, number]> = [];
46	  if (shouldCell11Survive || shouldCell11BeReproduced) {
47	    result.push([1, 1]);
48	  }
49	
50	  return result;
51	}
